4‚Üíexport default function HeroScene3D() {
5‚Üí  const mountRef = useRef(null)
6‚Üí
7‚Üí  useEffect(() => {
8‚Üí    const container = mountRef.current
9‚Üí    if (!container) return
10‚Üí
11‚Üí    // Respect reduced motion
12‚Üí    const prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches
13‚Üí    const isMobile = window.innerWidth < 768
14‚Üí
15‚Üí    // Scene setup
16‚Üí    const scene = new THREE.Scene()
17‚Üí    const W = container.clientWidth
18‚Üí    const H = container.clientHeight
19‚Üí
20‚Üí    const camera = new THREE.PerspectiveCamera(55, W / H, 0.1, 100)
21‚Üí    camera.position.z = 7
22‚Üí    camera.position.x = 1.2
23‚Üí
24‚Üí    const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: !isMobile })
25‚Üí    renderer.setSize(W, H)
26‚Üí    renderer.setPixelRatio(Math.min(window.devicePixelRatio, isMobile ? 1 : 2))
27‚Üí    renderer.setClearColor(0x000000, 0)
28‚Üí    container.appendChild(renderer.domElement)
29‚Üí
30‚Üí    // Colors matching portfolio palette
31‚Üí    const C1 = new THREE.Color('#38bdf8') // sky
32‚Üí    const C2 = new THREE.Color('#a78bfa') // violet
33‚Üí    const C3 = new THREE.Color('#f472b6') // pink
34‚Üí    const C4 = new THREE.Color('#34d399') // emerald
35‚Üí
36‚Üí    // ‚îÄ‚îÄ Main TorusKnot ‚îÄ‚îÄ
37‚Üí    const torusGeo = new THREE.TorusKnotGeometry(1.0, 0.3, isMobile ? 64 : 128, isMobile ? 8 : 24)
38‚Üí    const torusMat = new THREE.MeshBasicMaterial({
39‚Üí      color: C1,
40‚Üí      wireframe: true,
41‚Üí      transparent: true,
42‚Üí      opacity: 0.1,
43‚Üí    })
44‚Üí    const torusKnot = new THREE.Mesh(torusGeo, torusMat)
45‚Üí    scene.add(torusKnot)
46‚Üí
47‚Üí    // Inner glow mesh (solid, very transparent)
48‚Üí    const glowMat = new THREE.MeshBasicMaterial({
49‚Üí      color: C2,
50‚Üí      transparent: true,
51‚Üí      opacity: 0.02,
52‚Üí      side: THREE.DoubleSide,
53‚Üí    })
54‚Üí    const glowMesh = new THREE.Mesh(torusGeo, glowMat)
55‚Üí    scene.add(glowMesh)
56‚Üí
57‚Üí    // ‚îÄ‚îÄ Orbiting Icosahedrons ‚îÄ‚îÄ
58‚Üí    const orbiters = []
59‚Üí    const orbiterCount = isMobile ? 3 : 6
60‚Üí    const orbiterColors = [C1, C2, C3, C4, C1, C3]
61‚Üí    for (let i = 0; i < orbiterCount; i++) {
62‚Üí      const size = 0.08 + Math.random() * 0.12
63‚Üí      const geo = new THREE.IcosahedronGeometry(size, 0)
64‚Üí      const mat = new THREE.MeshBasicMaterial({
65‚Üí        color: orbiterColors[i % orbiterColors.length],
66‚Üí        wireframe: true,
67‚Üí        transparent: true,
68‚Üí        opacity: 0.25,
69‚Üí      })
70‚Üí      const mesh = new THREE.Mesh(geo, mat)
71‚Üí
72‚Üí      // Orbit parameters
73‚Üí      const orbit = {
74‚Üí        mesh,
75‚Üí        radius: 2.2 + Math.random() * 1.2,
76‚Üí        speed: 0.3 + Math.random() * 0.5,
77‚Üí        phase: (Math.PI * 2 * i) / orbiterCount + Math.random() * 0.5,
78‚Üí        tilt: Math.random() * Math.PI * 0.5,
79‚Üí        rotSpeed: 0.5 + Math.random() * 1.5,
80‚Üí      }
81‚Üí      orbiters.push(orbit)
82‚Üí      scene.add(mesh)
83‚Üí    }
84‚Üí
85‚Üí    // ‚îÄ‚îÄ Floating particles ‚îÄ‚îÄ
86‚Üí    const particleCount = isMobile ? 30 : 80
87‚Üí    const particleGeo = new THREE.BufferGeometry()
88‚Üí    const particlePositions = new Float32Array(particleCount * 3)
89‚Üí    const particleSizes = new Float32Array(particleCount)
