97‚Üí    particleGeo.setAttribute('size', new THREE.BufferAttribute(particleSizes, 1))
98‚Üí    const particleMat = new THREE.PointsMaterial({
99‚Üí      color: C1,
100‚Üí      size: 0.03,
101‚Üí      transparent: true,
102‚Üí      opacity: 0.4,
103‚Üí      sizeAttenuation: true,
104‚Üí    })
105‚Üí    const particles = new THREE.Points(particleGeo, particleMat)
106‚Üí    scene.add(particles)
107‚Üí
108‚Üí    // ‚îÄ‚îÄ Mouse tracking ‚îÄ‚îÄ
109‚Üí    const mouse = { x: 0, y: 0, targetX: 0, targetY: 0 }
110‚Üí    const onMouseMove = (e) => {
111‚Üí      mouse.targetX = (e.clientX / window.innerWidth) * 2 - 1
112‚Üí      mouse.targetY = -(e.clientY / window.innerHeight) * 2 + 1
113‚Üí    }
114‚Üí    window.addEventListener('mousemove', onMouseMove)
115‚Üí
116‚Üí    // ‚îÄ‚îÄ Animation ‚îÄ‚îÄ
117‚Üí    const clock = new THREE.Clock()
118‚Üí    let animId
119‚Üí
120‚Üí    function animate() {
121‚Üí      animId = requestAnimationFrame(animate)
122‚Üí      const t = clock.getElapsedTime()
123‚Üí      const speed = prefersReduced ? 0.15 : 1
124‚Üí
125‚Üí      // Smooth mouse interpolation
126‚Üí      mouse.x += (mouse.targetX - mouse.x) * 0.04
127‚Üí      mouse.y += (mouse.targetY - mouse.y) * 0.04
128‚Üí
129‚Üí      // Main torusKnot rotation + mouse tilt
130‚Üí      torusKnot.rotation.x = t * 0.12 * speed + mouse.y * 0.3
131‚Üí      torusKnot.rotation.y = t * 0.18 * speed + mouse.x * 0.3
132‚Üí      torusKnot.rotation.z = t * 0.06 * speed
133‚Üí
134‚Üí      // Pulse opacity
135‚Üí      torusMat.opacity = 0.08 + Math.sin(t * 0.8) * 0.04
136‚Üí      glowMat.opacity = 0.015 + Math.sin(t * 0.5) * 0.01
137‚Üí
138‚Üí      // Glow mesh follows with slight lag
139‚Üí      glowMesh.rotation.copy(torusKnot.rotation)
140‚Üí      glowMesh.rotation.x += 0.1
141‚Üí      glowMesh.rotation.y += 0.15
142‚Üí
143‚Üí      // Orbiting icosahedrons
144‚Üí      orbiters.forEach((o) => {
145‚Üí        const angle = t * o.speed * speed + o.phase
146‚Üí        o.mesh.position.x = Math.cos(angle) * o.radius
147‚Üí        o.mesh.position.y = Math.sin(angle) * o.radius * Math.cos(o.tilt)
148‚Üí        o.mesh.position.z = Math.sin(angle) * o.radius * Math.sin(o.tilt) * 0.5
149‚Üí        o.mesh.rotation.x = t * o.rotSpeed * speed
150‚Üí        o.mesh.rotation.y = t * o.rotSpeed * 0.7 * speed
151‚Üí      })
152‚Üí
153‚Üí      // Particles gentle drift
154‚Üí      const posArr = particles.geometry.attributes.position.array
155‚Üí      for (let i = 0; i < particleCount; i++) {
156‚Üí        posArr[i * 3 + 1] += Math.sin(t + i) * 0.001
157‚Üí        posArr[i * 3] += Math.cos(t * 0.5 + i * 0.3) * 0.0005
158‚Üí      }
159‚Üí      particles.geometry.attributes.position.needsUpdate = true
160‚Üí      particles.rotation.y = t * 0.02 * speed
161‚Üí
162‚Üí      // Color cycling
163‚Üí      const hue = (t * 0.05) % 1
164‚Üí      torusMat.color.setHSL(hue * 0.15 + 0.55, 0.8, 0.65)
165‚Üí
166‚Üí      renderer.render(scene, camera)
167‚Üí    }
168‚Üí    animate()
169‚Üí
170‚Üí    // ‚îÄ‚îÄ Resize ‚îÄ‚îÄ
171‚Üí    const onResize = () => {
172‚Üí      const w = container.clientWidth
173‚Üí      const h = container.clientHeight
174‚Üí      camera.aspect = w / h
175‚Üí      camera.updateProjectionMatrix()
176‚Üí      renderer.setSize(w, h)
177‚Üí    }
178‚Üí    window.addEventListener('resize', onResize)
179‚Üí
180‚Üí    return () => {
181‚Üí      cancelAnimationFrame(animId)
182‚Üí      window.removeEventListener('mousemove', onMouseMove)
183‚Üí      window.removeEventListener('resize', onResize)
184‚Üí      renderer.dispose()
185‚Üí      torusGeo.dispose()
186‚Üí      torusMat.dispose()
187‚Üí      glowMat.dispose()
188‚Üí      particleGeo.dispose()
189‚Üí      particleMat.dispose()
190‚Üí      orbiters.forEach((o) => {
